(() => {
  'use strict';

  if (window.__docsRocketCompatLoaded) return;
  window.__docsRocketCompatLoaded = true;

  const reactivateApplicationScripts = () => {
    document.querySelectorAll('script[type$="-text/javascript"]').forEach((source) => {
      if (source.dataset.docsReactivated === 'true') return;

      const code = source.textContent || '';
      const isCloudflareChallenge = code.includes('__CF$cv$params') || code.includes('challenge-platform/scripts');
      const isApplicationScript =
        code.includes('document.querySelectorAll') ||
        code.includes('IntersectionObserver') ||
        code.includes('showModal') ||
        code.includes('remoteImages');

      if (isCloudflareChallenge || !isApplicationScript) return;

      source.dataset.docsReactivated = 'true';
      const executable = document.createElement('script');
      executable.textContent = code;
      source.insertAdjacentElement('afterend', executable);
    });
  };

  const loadGlobalSiteScript = () => {
    if (document.querySelector('script[data-docs-global-site]')) return;

    const script = document.createElement('script');
    script.src = '/assets/js/site.js';
    script.defer = true;
    script.dataset.docsGlobalSite = 'true';
    document.head.appendChild(script);
  };

  reactivateApplicationScripts();
  loadGlobalSiteScript();
})();
